import React, { useState, useEffect } from "react";
import image1 from "../assets/ab-hl-2.jpg";
import image2 from "../assets"

const About = () => {
  const images = [image1]; // add more images if needed
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrent(prev => (prev + 1) % images.length);
    }, 3000); // change slide every 3 seconds
    return () => clearInterval(interval);
  }, [images.length]);

  // Inline CSS
  const styles = {
    container: {
      position: "relative",
      width: "100%",
      maxWidth: "900px",
      margin: "auto",
      overflow: "hidden",
    },
    slider: {
      position: "relative",
    },
    image: {
      width: "100%",
      height: "400px",
      objectFit: "cover",
      transition: "opacity 1s ease-in-out",
    },
    text: {
      position: "absolute",
      bottom: "20px",
      left: "20px",
      color: "white",
      background: "rgba(0,0,0,0.4)",
      padding: "15px",
      borderRadius: "10px",
      maxWidth: "80%",
    },
  };

  return (
    <div style={styles.container}>
      <div style={styles.slider}>
        <img src={images[current]} alt="slide" style={styles.image} />
        <div style={styles.text}>
          <h2>About Our Website</h2>
          <p>
            This website was created to provide services like Pathology, Medicine, Consultancy, and Bloodbank.
            We strive to deliver the best experience to our customers.
          </p>
        </div>
      </div>
    </div>
  );
};

export default About;
